    let string = null;
    let error = null;

    try {
        string = JSON.stringify(message);
    }
    catch (err) {
        error = err;
    }

    if (options.replace) {
        Object.keys(options.replace).forEach((token) => {

            string = string.replace(`"${token}"`, options.replace[token]);
